jQuery(document).ready(function(t){const e=t("#taxonomy_id"),n=t("#category-rows-wrapper");e.select2({placeholder:"-- Select Taxonomy --",allowClear:!0,width:"350px"}),e.on("change",function(){const e=t(this).val();if(n.empty(),categoriesByTax[e]){const t=(new Date).toISOString().split("T")[0];categoriesByTax[e].forEach(e=>{const a=`\n                    <div class="item-row" id="row-${e.id}" style="margin-bottom:15px; border-bottom:1px solid #ddd; padding:10px;">\n                        <strong>${e.category_name}</strong>\n                        <input type="hidden" class="taxonomy-category-id" value="${e.id}">\n                        <div style="margin-top:5px;">\n                            <label>Buy Price: </label>\n                            <input type="number" step="0.01" class="buy-price" style="width:100px;">\n                            <label>Sell Price: </label>\n                            <input type="number" step="0.01" class="sell-price" style="width:100px;">\n                            <label>Date: </label>\n                            <input type="date" class="price-date" value="${t}" style="width:150px;">\n                            <button class="add-item-single button button-primary" data-row-id="${e.id}">Add</button>\n                        </div>\n                    </div>\n                `;n.append(a)})}})});
